
# 中腾微网PCS数据点表

from __future__ import annotations
from dataclasses import dataclass
from typing import List, Optional, Tuple, Mapping


@dataclass(frozen=True)
class PCSRegisterDefinition:
    address: int
    length: int
    field_name: str
    label_cn: str
    attribute: str
    unit: str
    scale: float
    scale_decimals: int
    data_type: str
    group: str
    models: Tuple[str, ...]
    bit_index: Optional[int] = None
    enum_values: Optional[Mapping[int, str]] = None

    def addresses(self) -> List[int]:
        return list(range(self.address, self.address + self.length))


GROUP_HEARTBEAT = "心跳组"
GROUP_CORE      = "实时组"
GROUP_STATIC    = "静态组"
GROUP_CONTROL   = "控制组"

READ_REGISTER = 0x03
WRITE_REGISTER = 0x06

