def load_pcs_register_map(model: Optional[str] = None,group: Optional[str] = None,) -> List[PCSRegisterDefinition]:
    definitions = list(PCS_REGISTER_MAP)
    if model:
        definitions = [d for d in definitions if model in d.models]
    if group:
        definitions = [d for d in definitions if d.group == group]
    return definitions

